Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (75,'한국은행화폐박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2730&fileTy=POSTTHUMB&fileNo=5&thumbTy=M','한국은행본관에서는 국내·외 화폐 20,000여 점의 전시를 비롯해 화폐의 제조과정부터 한국 경제의 발전과정까지 방대한 자료를 제공하고 있다.','100-794 서울특별시 중구 남대문로 39, 한국은행건물 (남대문로3가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (76,'세빛섬','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24645&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','세빛섬은 서울 도심 한가운데의 한강 수변에서 문화와 여가를 즐길 수 있는 문화 복합공간이자 랜드마크다.','06500 서울 서초구 올림픽대로 2085-14 (반포동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (77,'보신각(상설타종행사)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1904&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','보신각은 서울 종로구 종로 2가에 있는 종각으로 서울보신각종을 걸어 놓기 위해 만든 것이다.','03189 서울 종로구 종로 54 (관철동, 보신각)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (78,'국회의사당','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5765&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','여의도에 위치한 국회의사당은 한국의 민주주의와 인권을 상징하는 건물이다. 국회의사당 본관이 있고 그 오른쪽에는 국회도서관이, 왼쪽에는 의원회관이 있다.','07233 서울특별시 영등포구 의사당대로 1 (여의도동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (79,'국립현대미술관 덕수궁관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1708&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','국립현대미술관 덕수궁관은 1998년 덕수궁 내 분관으로 개관하였다.','04519 서울특별시 중구 세종대로 99 (정동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (80,'도산공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1789&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','도산공원은 서울 강남구 신사동에 있는 공원으로 도산 안창호의 애국정신과 교육 정신을 기리고자 조성되었다.','06020 서울 강남구 도산대로45길 20 (도산전시관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (81,'정릉','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3461&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','정릉은 태조의 계비 신덕왕후의 능으로, 극진히 사랑했던 신덕왕후가 갑자기 승하하자 태조는 도성 안 덕수궁 뒤편에 능역을 조성했다.','02813 서울 성북구 아리랑로19길 116 (정릉동, 정릉)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (82,'안중근의사기념관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4281&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','안중근의사 기념관은 1909년 이토 히로부미를 사살한 독립운동가 안중근 의사를 추모하는 기념관이다.','04636 서울 중구 소월로 91 (남대문로5가, 안중근의사기념관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (83,'아름다운 차박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4471&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','종로구 인사동에 위치한 아름다운 차 박물관에서는 차와 관련된 유물을 수집, 관리 및 전시하고 있다.','03162 서울 종로구 인사동길 19-11',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (84,'국립어린이민속박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5134&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','국립어린이민속박물관에서는 어린이를 대상으로 한국의 전통문화를 직접 배울 수 있는 체험프로그램을 제공한다.','03045 서울 종로구 삼청로 37 (세종로, 국립민속박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (85,'환구단(원구단)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4198&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','환구단은 하늘에 천자가 제사를 드리는 제천단이다.','서울시 중구 소공로 106 (소공동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (86,'한성백제박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11610&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','한성백제박물관은 송파구의 고대역사 유적지에 설립된 시립박물관으로 백제의 역사와 유적을 보존하고 있는 곳이다.','05540 서울 송파구 위례성대로 71 (방이동, 한성백제박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (87,'서울올림픽기념관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5334&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울올림픽기념관은 88서울올림픽을 기념하고 올림픽 정신을 계승 및 발전하고자 설립되었다.','05540 서울 송파구 올림픽로 424 (방이동, 올림픽공원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (88,'북악스카이웨이 팔각정','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11117&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서울 하늘에 맞닿은 전망대연인들의 데이트 코스로 손꼽히는 북악스카이웨이는 남산서울타워와는 또 다른 각도로 서울 전체를 볼 수 있는 곳이다.','03010 서울시 종로구 북악산로 267 (평창동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (89,'약현성당','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1846&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','중구 중림동에 있는 약현성당은 우리나라 최초의 서양식 벽돌조 고딕성당이다.','04506 서울시 중구 청파로 447-1',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (90,'의학박물관 (구 대한의원)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=846&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','의학박물관(구 대한의원)은 서울대학교 의과대학에 있는 조선 말기의 건물이다.','03080 서울특별시 종로구 대학로 101 (연건동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (91,'배재학당역사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6433&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','배재학당역사박물관은 한국 최초의 서양식 학교건물이자 근대식 중등 교육기관이다. 옛 배재학당의 교실로 사용된 바 있으며 현재는 상설전시관, 기획전시관, 체험교실, 세마나실로 조성되어 있다.','04516 서울특별시 중구 서소문로11길 19, 배재정동빌딩 동관 (정동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (92,'창의문','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3266&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','서울 성곽의 4소문 중 하나로 북문 또는 자하문으로도 불리는 창의문은 서울 종로구 청운동에 자리해있는 조선시대 성문이다.','03020 서울특별시 종로구 창의문로 118 (부암동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (93,'쇳대박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1427&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','2003년 대학로에 적갈색의 건축물 하나가 들어섰다. 승효상의 쇳대박물관이다. 승효상은 코르텐 강(내후성 강판, 녹슨 철의 느낌) 소재로 자신의 미학을 드러냈다.','110-810 서울특별시 종로구 이화장길 100 (동숭동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (1,'양화진외국인선교사묘원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1153&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','양화진외국인선교사묘원은 서울 마포구 합정동에 위치한 외국인 선교사들의 공동묘지이다.','04084 서울 마포구 양화진길 46 (합정동, 양화진홍보관)',180);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (2,'호림박물관 (신사분관)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5548&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','호림박물관 신사분관은 총 세 개의 건물로 이루어져 있으며, 그중 5층 규모의 박물관동 2, 3, 4층에서 고미술품을 비롯한 현대 작가들의 기획전을 전시하고 있다.','06021 서울 강남구 도산대로 317 (신사동, 호림아트센터 1빌딩)',43);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (3,'갤러리 학고재','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1872&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','갤러리 학고재는 ‘옛것을 배워 새것을 만든다’는 이념을 담고 있다. 갤러리 학고재의 본관 건물은 전통 한옥으로, 신관 건물은 21세기 건축 양식으로 만들어져 개성 있게 조화를 이루고 있다.','03053 서울특별시 종로구 삼청로 50 (소격동)',27);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (4,'송은(SONGEUN)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3778&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','송은은 송은미술대상, 국내외 작가 개인전, 특정 국가 기획전 및 컬렉션전 등의 기획전시와 더불어 국내외 동시대 미술을 조명하고 미술과 대중을 연결하고자 다양한 프로그램을 선보이는 비영리 문화공간이다.','06016 서울 강남구 도산대로 441 (청담동)',4);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (5,'김종영 미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2066&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','김종영 미술관은 한국현대조각의 선구자로 불리는 조각가 김종영을 기리며 동시에 젊은 작가들을 후원하기 위해 설립되었다.','03004 서울특별시 종로구 평창32길 30 (평창동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (6,'경희대학교 한의학역사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6889&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','경희대학교 한의학 역사박물관에는 고전 의서, 임상기록, 한의학에 관련한 유물 등이 전시되어 있다.','02453 서울 동대문구 경희대로 26-6 (회기동, 경희대학교)',28);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (7,'경복궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=72&fileTy=POSTTHUMB&fileNo=6&thumbTy=M','조선 왕조 개국 3년인 1395년에 완공된 경복궁은 이때부터 한양의 중심이 되었다. 조선왕조의 정궁으로 큰 규모와 보다 엄격한 격식이 특징적이다.','03045 서울 종로구 사직로 161 (세종로, 경복궁)',3);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (8,'창덕궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=295&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','세계가 보존하는 세계문화유산창덕궁은 서울에서 두 번째로 유네스코 선정 세계문화유산으로 등재되었다. 가장 먼저 종묘가 선정됐고 이어 창덕궁이 등재됐다.','03072 서울 종로구 율곡로 99 (와룡동, 창덕궁)',4);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (9,'전쟁기념관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=859&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','전쟁기념관에 들어서면 ''형제의 상''이 가장 먼저 눈에 들어온다. 현대사의 슬픔을 고스란히 보여준다.','04353 서울 용산구 이태원로 29 (용산동1가, 전쟁기념관)',27);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (10,'국립중앙박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=433&fileTy=POSTTHUMB&fileNo=11&thumbTy=M','한국 역사와 문화의 정수가 살아 숨 쉬는 국립중앙박물관은 연간 350만명의 관람객을 맞이하는 한국 최대 규모의 국립 박물관입니다. 세계 많은 나라의 문화를 소개하는 세계문화관과 최첨단 디지털 기술로 구현된 실감영상관 및 VR체험관에서 더욱 즐거운 국립중앙박물관을 만나보세요!','04383 서울 용산구 서빙고로 137 (국립중앙박물관)',19);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (11,'봉은사','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=411&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','삼성역 맞은편엔 비교적 큰 규모의 사찰이 있다. 바로 봉은사다. 서울의 대표적인 사찰로 그 역사만도 1000년이 넘는다.','06087 서울 강남구 봉은사로 531 (봉은사)',20);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (12,'명동성당','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4037&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','명동성당은 우리나라 최초의 본당이며 한국 천주교회의 상징이다. 고종 29년(1892)에 착공, 광무 2년(1898)에 준공되었다.','04537 서울 중구 명동길 74 (명동성당)',8);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (13,'조계사','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2587&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서울 종로구 견지동에 있는 사찰인 조계사는 한국 불교의 중심 사찰이다. 조계라는 명칭은 혜능대사가 머물렀던 조계산에서 가져왔다고 한다.','03144 서울특별시 종로구 우정국로 55 (조계사)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (27,'아라리오뮤지엄 인 스페이스','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=20731&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','아라리오뮤지엄은 ㈜아라리오의 창업자인 김창일 회장이 설립한 아트뮤지엄이다. 서울에 설립된 아라리오 뮤지엄은, 김수근 건축가의 대표작인 동시에 그의 사무실과 자택으로도 사용되는 등 건축사적으로 의미가 깊다.','03058 서울 종로구 율곡로 83 (원서동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (28,'롯데월드 민속박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5815&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','잠실 롯데월드 내 자리한 롯데월드 민속박물관은 시대별로 유물이 전시된 역사전시관, 조선시대 궁중의 의례장면을 축소 후 재현해 놓은 모형 촌, 전통공예품 제작과정을 볼 수 있는 저잣거리, 놀이마당 등으로 구성되어 있다.','05554 서울 송파구 올림픽로 240 (잠실동, 롯데월드)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (29,'고려대학교 본관 및 구 중앙도서관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2962&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','고려대학교 본관은 서울특별시 성북구 안암동에 있는 고려대학교의 대학본부 건물로 1981년 사적 제285호로 지정되었다.','02841 서울 성북구 안암로 145 (안암동5가, 고려대학교안암캠퍼스)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (30,'국립서울현충원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1965&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','국립현충원은 나라와 민족을 위해 순국한 영령들이 안장된 국립묘지이다. 국가유공자의 유골, 유해를 안장하고, 그 충과 의를 기리기 위해 설립되었다.','06984 서울 동작구 현충로 210 (동작동, 국립현충원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (31,'길상사','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3256&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','옛 가옥 같은 절집도심과 10분 거리에 있는 시골 같은 동네, 계곡 양쪽으로 빈부가 마주보고 있는 성북동 중턱에 고즈넉한 길상사가 자리 잡고 있다. 백제나 신라 때 세워진 유서 깊은 절에 비해 역사는 짧지만 개원하면서부터 지금까지 수많은 사람들의 발길이 끊이지 않으며,','136-022 서울특별시 성북구 선잠로5길 68 (성북동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (32,'서대문자연사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2615&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서대문자연사박물관은 서대문구에 위치한 국내 최초로 공공기관이 직접 계획하고 설립한 자연사박물관이다.','03718 서울특별시 서대문구 연희로32길 51 (연희동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (33,'한국가구박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3452&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','한국가구박물관은 한국 전통 목가구 2,500여 점을 수집, 보존, 전시하는 특수 전문 박물관으로 한국의 옛 가옥 10여 채를 옮겨 놓아 실제 한옥에서 우리 가구의 쓰임새와 생활 방식을 총체적으로 볼 수 있다.','02822 서울 성북구 대사관로 121 (성북동, 한국가구박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (34,'국립중앙박물관 어린이박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=20547&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','국립중앙박물관 어린이박물관에는 다양한 옛사람들의 생활 모습을 전시하고 있다.','04383 서울 용산구 서빙고로 137 (용산동6가, 국립중앙박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (35,'명동관광정보센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11469&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','명동 관광정보센터는 서울 중구 을지로2가에 위치해 있는 관광안내소이다.','04538 서울시 중구 을지로 66 한국외환은행',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (36,'대한성공회서울주교좌성당(서울성공회성당)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2030&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','대한성공회 서울주교좌성당은 서울 중구 정동에 위치해 있다.','서울특별시 중구 세종대로21길 15 (정동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (37,'서울도서관 (옛 서울시청사)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=10231&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울도서관은 옛 서울시 시청사를 개조하여 만들어진 공공도서관이다.','04524 서울특별시 중구 세종대로 110 (태평로1가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (38,'청계천박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4696&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','청계천박물관은 지하 2층, 지상 4층 규모로 상설전시실, 기획전시실, 교육실, 소강당 등이 마련돼 있다.','04704 서울 성동구 청계천로 530 (마장동, 청계천박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (39,'화계사','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2021&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','화계사는 강북구 수유동 삼각산 숲 내에 위치한 사찰로 도심과도 인접해 있어 자연의 정취를 느끼고자 많은 시민이 방문하고 있다.','01095 서울 강북구 화계사길 117 (수유동, 화계사)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (40,'연세대학교 스팀슨관&언더우드관&아펜젤러관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2435&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','연세대학교 스팀슨관은 신촌동 연세대학교에 있는 근대식 건물로 1981년 사적 제275호로 지정되었다.','03722 서울특별시 서대문구 연세로 50 (신촌동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (41,'가회민화박물관　','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=18912&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','가회 민화박물관은 민화 전문 박물관으로 윤열수 관장이 개인적으로 꾸준히 수집해 온 민화와 부적관계 자료 등을 일반인들에게 공개하고 보존하기 위해 설립되었다.','03056 서울 종로구 북촌로 52 (가회동) 가회민화박물관',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (42,'국립국악원박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11897&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','국립국악원박물관은 우리나라 최초의 국악 전문박물관으로 우리 고유음악의 장점을 배우고 느낄 수 있는 곳이다.','06757 서울 서초구 남부순환로 2364 (서초동, 국립국악원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (43,'국립중앙도서관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11012&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','국립중앙도서관은 한국의 지적문화유산을 체계적으로 수집해 보관하고 있는 우리나라 대표 도서관이다.','서울특별시 서초구 반포대로 201 (반포동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (44,'갤러리 현대','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1694&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','갤러리 현대는 사간동 갤러리 거리에서 가장 유명하다.','03062 서울 종로구 삼청로 14 (사간동, 현대갤러리)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (45,'금호미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3100&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','경복궁 근처에 위치한 금호미술관에서는 기성작가의 기획전을 비롯해 뛰어난 신인 작가의 기획전을 동시에 감상할 수 있다.','03062 서울 종로구 삼청로 18 (사간동, 금호미술관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (46,'헌인릉','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5242&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','헌인릉은 조선 제3대 임금인 태종과 왕비의 능인 헌릉과 제23대 순조와 왕비의 인릉을 합쳐 부르는 말이다.','06795 서울 서초구 헌인릉길 36-10 (헌인릉)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (47,'뮤지엄김치간','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=19924&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','삼성동에 위치해 있던 풀무원김치박물관이 ''뮤지엄김치간''으로 새롭게 태어났다. 뮤지엄김치간은 다양한 종류의 김치를 모형이 아닌 실물로 전시하고 있어, 직접 눈으로 관람할 수 있다.','03149 서울 종로구 인사동길 35-4 (관훈동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (48,'국제갤러리','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3241&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','1982년 개관한 국제갤러리는 대표적인 국내 화랑으로서 세계적으로 유명한 현대미술 작가의 작품과 그 흐름을 접하고 감상할 수 있는 곳이다.','100-200 서울특별시 종로구 삼청로 54 (소격동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (49,'아라리오갤러리 서울','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2388&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','아시아를 대표하는 아라리오 갤러리는 서울, 천안, 중국 상하이에 운영 중이다','03053 서울특별시 종로구 북촌로5길 84 (소격동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (123,'서울생활사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=38243&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울생활사박물관은 근현대 생활사 박물관으로 시민들의 기억들을 추억하고 교감할 수 있는 전시들과 프로그램이 운영되는 장소이다.','01849 서울 노원구 동일로174길 27 (공릉동) 서울생활사박물관',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (124,'서울공예박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=38092&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','공예의 가치를 공유하며 공예의 미래를 여는 열쇠가 되기를 지향하는 박물관','03061 서울 종로구 율곡로3길 4 (안국동, 서울공예박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (50,'한상수자수박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3358&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','중요무형문화재 제80호이자 자수장 기능보유자 한상수가 개관한 한상수 자수 박물관은 중요 방직 문화유산과 민속품을 통해 한국 전통 자수의 우수성을 알리고 있다.','02836 서울 성북구 성북로16길 4-10 (성북동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (51,'종이나라박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5797&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','종이나라 박물관에서는 어린이와 학생들에게 종이의 역사와 한국 종이문화의 발전과정을 견학과 체험학습을 통해 소개하고 있다.','04606 서울 중구 장충단로 166 (장충동1가, 종이나라빌딩)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (52,'북촌동양문화박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5668&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','북촌한옥마을이 자리한 북촌동양문화박물관에서는 설립자 권영두 과장이 30년 동안 수집 및 소장한 한국과 아시아 문화 예술품을 전시하고 있다.','03052 서울 종로구 북촌로11길 76',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (53,'서울약령시 한의약박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4632&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','우리나라 최대 한약 유통시장인 약령시에 있는 한의약 박물관','02570 서울 동대문구 약령중앙로 26 (제기동, 서울한방진흥센터) B2',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (54,'겸재정선미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1961&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','겸재정선미술관은 서울 강서구 양천로에 위치해 있으며 지하 1층, 지상 3층으로 이루어져 있다.','07522 서울 강서구 양천로47길 36 (가양동, 겸재정선미술관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (55,'토탈미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3085&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','토탈미술관에는 전시장, 미술관 아카데미, 자료실, 아트숍, 야외 공연장 등이 마련되어 있다.','03004 서울 종로구 평창32길 8',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (56,'남산서울타워','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=36&fileTy=POSTTHUMB&fileNo=8&thumbTy=M','도심 속 로맨틱 아일랜드로 입지를 굳힌 남산서울타워는 예로부터 백년해로의 길지로 널리 알려진 남산(262m) 정상에 위치한 높이 236.7m의 탑으로, 해발 480m 위치에서 서울시를 360도 파노라마 뷰로 조망할 수 있는 최고의 전망을 자랑한다..','04340 서울 용산구 남산공원길 105 (용산동2가, YTN서울타워)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (57,'북촌한옥마을','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=261&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','600년 수도의 스펙트럼 속으로서울에서 가장 생생하게 살아 숨 쉬는 역사문화의 현장은 단연 북촌한옥마을이다. 600년 수도의 역사를 자랑하듯 전통 한옥들이 즐비한 동네다.','03059 서울 종로구 계동길 37 북촌문화센터 일대 (계동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (58,'서초관광정보센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11992&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서초관광정보센터는 문화와 예술이 자연과 함께 어우러져 있고, 패션, 뷰티와 비즈니스의 중심지인 강남역 9번 출구 뒤편에 위치해 있다.','06615 서울 서초구 강남대로 399 (서초동, 몬테소리)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (59,'덕수궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2049&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','덕수궁에 들어가기 위해 태평로의 상징인 대한문을 지난다. 하지만 원래의 위치는 아니다. 일제에 의해 태평로가 만들어지면서 덕수궁의 크기는 줄어들었고 대한문도 뒤쪽으로 물러났다.','04519 서울 중구 세종대로 99',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (60,'종묘','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=507&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','왕의 위패를 모시고 제를 올리는 종묘는 조선의 역사에 더없이 중요한 장소였다. 임금이 새로 왕위에 오르면 가장 먼저 종묘와 사직에 나아가 절을 하며 제사를 드렸다.','03135 서울 종로구 종로 157 (훈정동, 종묘공원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (61,'광화문광장 야경','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=16319&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','인왕산 자락을 배경으로 600년을 내려온 서울 경관의 중심이자 우리 민족의 얼이 담긴 장소','03154 서울특별시 종로구 세종대로 172',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (62,'광화문광장','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1900&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','조선 태조는 1394년에 도읍을 한양으로 옮기고 정국인 경복궁을 지었다. 그리고 궁의 정문인 광화문 앞 길의 좌우에 의정부를 포함해 육조 관아 거리를 건설했다.','03154 서울특별시 종로구 세종대로 172',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (63,'흥인지문(동대문)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1999&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','한성부의 동쪽을 지키던 큰 대문보물 제1호 흥인지문(興仁之門)은 옛날 중요한 국가 시설이 있던 한성부를 보호하기 위해 만든 서울 성곽의 여덟 성문 가운데 동쪽의 큰 대문에 해당한다.','03119 서울 종로구 종로 288 (종로6가, 흥인지문)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (64,'숭례문(남대문)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=22888&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서울 도성의 남쪽 정문이라서 통칭 남대문(南大門)이라고 불린다. 1395년(태조 4)에 짓기 시작하여 1398년(태조 7)에 완성되었고, 1447년(세종 29)에 개축하였다.','04528 서울 중구 세종대로 40 (숭례문(남대문))',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (65,'63스퀘어','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=252&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','여의도 63빌딩은 볼거리, 먹을거리, 즐길거리 등을 갖춘 복합 공간이다. 빌딩의 맨 꼭대기, 63 스카이텍은 전망 하나만으로 모든 걸 압도한다.','07345 서울 영등포구 63로 50 (여의도동, 63한화생명빌딩)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (66,'문화역서울 284','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=450&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','문화역서울284는 일제 강점기 당시 건축된 서울역사로 현재는 복합문화공간으로써 사용되고 있다.','04509 서울 중구 통일로 1 (서울역 본옥)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (67,'청와대','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5538&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서울 종로구에 자리해 있는 청와대는 대한민국 대통령의 관저이다. 본관에는 대통령 집무실, 접견실, 회의실, 주거실 등이 있다.','03048 서울 종로구 청와대로 1 (세종로)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (14,'예술의 전당 한가람미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4325&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','한가람미술관은 예술의 전당 전면의 왼쪽에 위치해 있다.','06757 서울특별시 서초구 남부순환로 2406 (서초동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (15,'롯데월드타워','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=21278&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','글로벌 상징성과 한국의 전통미, 인간과 기술, 첨단과 자연이 공존하는 롯데월드타워는 하나의 건축물에 도시생활의 모든 것을 구현한 수직도시이다.','05551 서울 송파구 올림픽로 300 (신천동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (16,'창경궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=297&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','창경궁은 1483년 창덕궁 동쪽에 세워진 궁으로, 성종이 정희왕후, 안순왕후, 소혜왕후를 위해 수강궁을 확장하면서 창경궁이라는 이름을 붙였다.','03072 서울 종로구 창경궁로 185 (와룡동, 창경궁)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (17,'리움 미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1232&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','한남동 언덕길을 오르다 보면 리움 미술관과 만나게 된다. 삼성그룹의 창립자 고 이병철 회장의 수집품에서 출발한 미술관이다.','04348 서울 용산구 이태원로55길 60-16 (한남동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (18,'몽촌역사관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5507&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','올림픽공원 내에 위치한 몽촌역사관은 백제시대 대표적인 유적 들을 볼 수 있는 곳으로 몽촌토성과 풍납토성의 출토물도 전시하고 있다.','05540 서울 송파구 올림픽로 424 (몽촌역사관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (19,'삼청동 골목길','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2121&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서울에서 가장 스타일리시한 골목, 삼청동','서울특별시 종로구 가회동 일대',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (20,'서대문형무소역사관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1833&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서대문형무소는 현존하는 건축물 중 유일한 일본풍 목조 건물이다. 1923년 지은, 사형 선고를 받고 투옥된 전국의 애국지사들이 이감 후 생을 마감한 장소다.','03732 서울 서대문구 통일로 251 (현저동, 독립공원)',1);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (21,'서울역사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2723&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','2002년, 선사 시대부터 현대까지 서울의 역사와 문화를 정리하여 보여줄 서울역사박물관이 경희궁터에 문을 열었다.','03177 서울 종로구 새문안로 55 (신문로2가, 서울역사박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (22,'국립현대미술관 서울관 갤러리아트존','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=16792&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','국립현대미술관과 현대자동차의 협업으로 탄생한 갤러리 아트존은 문화상품 발굴, 차세대 작가들의 전시 및 상품제작 등을 통해 관람객들과의 보다 폭 넓은 소통의 장으로 예술의 문턱을 낮춰 문화저변을 확대해나가고 있다.','03062 서울 종로구 삼청로 30 (소격동) 국립현대미술관',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (23,'국립현대미술관 서울관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11659&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','국립현대미술관 서울관은 민현준 건축가에 의해 설계되어 ''문화의 거리'' 삼청로에 2013년 11월 개관하였다.','03062 서울 종로구 삼청로 30 (소격동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (24,'서울 한양도성','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=90&fileTy=POSTTHUMB&fileNo=6&thumbTy=M','한양도성은 1396년 현재 서울의 도심부를 감싸고 있는 백악·낙타·목멱·인왕의 능선을 따라 처음 축조된 이후 여러 차례 개축되었다.','03098 서울 종로구 율곡로 283 (종로6가, 서울디자인지원센터)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (25,'경희대학교 중앙박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6927&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','경희대학교 중앙박물관은 경희대학교 부속 박물관으로 1955년 설립되었다.','02447 서울특별시 동대문구 경희대로 26 경희대학교 서울캠퍼스 중앙도서관 4층',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (26,'서울중앙성원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4867&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','용산구 한남동에 있는 이슬람 서울중앙성원은 대한민국에 이슬람교와 아랍문화를 알리고, 이슬람 국가와의 원만한 교류를 위해 설립되었다.','04405 서울 용산구 우사단로10길 39',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (68,'국립고궁박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=20550&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','국립고궁박물관은 500년 역사를 자랑하는 조선시대의 왕실 유물과 문화재를 전시한다.조선시대의 왕들이 직접 쓴 글씨와 시, 각종 유물들이 전시되어 있다.','03045 서울 종로구 효자로 12 (세종로, 국립고궁박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (69,'선정릉(선릉)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1414&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','삼릉공원 안에 성종과 정현왕후의 능인 선릉(宣陵)과, 아들 중종의 능 정릉(靖陵)이 있는 곳','06153 서울특별시 강남구 선릉로100길 1 (삼성동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (70,'운현궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=471&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','운현궁은 조선 후기 흥선대원군의 사가이다. 흥선대원군의 둘째 아들 고종이 출생하여 왕위에 오르기 전까지 성장한 곳이다.','03131 서울 종로구 삼일대로 464 (운현궁)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (71,'서울시립미술관 (서소문본관)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1525&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','덕수궁 돌담길 옆 아름다운 미술관운치 있는 덕수궁 돌담길을 서서히 돌아 정동길로 접어들면 왼쪽으로 오래된 수목과 꽃들이 어우러진 아름다운 야외 정원이 시선을 잡아끈다.','04515 서울 중구 덕수궁길 61 (서소문동, 서울시립미술관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (72,'서울광장','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1539&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울에서 신발을 벗고 걸을 수 있는 곳. 따스한 햇살을 이불 삼아 낮잠을 청할 수 있는 곳. 바로 서울광장이다.','100-101 서울특별시 중구 세종대로 110 (태평로1가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (73,'대한민국역사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6668&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','대한민국역사박물관은 19세기 말 개항기부터 오늘날에 이르는 대한민국의 역사를 종합적, 체계적으로 보여주는 국내 최초의 국립 근현대사박물관이다.','03141 서울시 종로구 세종대로 198 (세종로)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (74,'경희궁','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1159&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','경희궁은 본래 인조의 아버지인 정원군의 집이었으나, 그 터에 왕기가 서려 있다는 말이 돌자 광해군이 이를 몰수해 궁궐을 지었다.','03177 서울 종로구 새문안로 45 (경희궁)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (150,'서울역사박물관 온라인 교육 서비스','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=33743&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','"언제 어디서나 만날 수 있는 박물관" 서울역사박물관 온라인 교육 서비스','03177 서울 종로구 새문안로 55 (신문로2가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (151,'용산공예관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=33266&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','공예문화의 과거와 현재, 도시와 도시를 이어주는 네트워크 플랫폼 : 용산공예관','04399 서울 용산구 이태원로 274 (한남동, 용산전통공예문화체험관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (152,'서울특별시청서소문별관정동전망대','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=32889&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','정동전망대라고도 불리는 서울특별시청서소문별관정동전망대에서는 아름다운 덕수궁의 모습을 한눈에 볼 수 있는 곳이다.','04515 서울 중구 덕수궁길 15 (서소문동, 서울시청 서소문별관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (153,'안녕인사동','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=32734&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','안녕인사동은 어제, 오늘, 내일을 잇는 공간을 담아 추억과 즐거움을 선사하는 문화복합몰이다.','03145 서울 종로구 인사동길 49 (관훈동) 안녕인사동',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (154,'대림시장 감자국거리','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=32546&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','응암동에 위치한 대림시장 감자국거리는 1980년대 중반 이후 대림시장에 자리 잡고 있던 식당들이 돼지 등뼈와 감자, 우거지 등을 넣고 끓인 감자국을 팔기 시작하면서 감자국거리가 형성되었다. 현재는 응암동의 명소로 많은 사랑을 받고 있다.','03351 서울 은평구 통일로78길 22-11 (스카이힐튼) 대림시장 감자국거리',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (155,'정동1928 아트센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=32529&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','정동1928 아트센터는 1928년에 구세군 사관양성 및 선교와 사회사업을 위한 본부로 이용하기 위한 건축물로 완공되었다.','04519 서울 중구 덕수궁길 130 (정동, 구세군중앙회관) 정동1928 아트센터',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (156,'형제대장간','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=32528&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','수색역에서 도보 5분 거리에 위치한 40여 년의 세월의 역사가 살아 숨 쉬는 형제대장간은 형제가 함께 운영하고 있으며, 농기구, 건축 기구뿐 아니라 모든 품목을 생산한다.','03504 서울 은평구 수색로 249 (수색동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (157,'서소문성지역사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=30804&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','서소문성지역사박물관은 조선 후기 한국 교회사를 한눈에 살펴볼 수 있는 역사박물관이다.','04510 서울 중구 칠패로 5 (의주로2가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (158,'아모레퍼시픽미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=30803&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','아모레퍼시픽 미술관은 서울시 용산의 아모레퍼시픽 신본사에 새롭게 문을 연 미술관이다.','04386 서울 용산구 한강대로 100 (한강로2가, 아모레퍼시픽)',0);
