Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (161,'성우이용원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=29716&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','1927년 개원한 성우이용원은 옛 모습을 그대로 간직해 ''서울미래유산''으로 지정된 이발소이다.','04183 서울 마포구 효창원로97길 4-1 (공덕동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (162,'개미슈퍼','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=29715&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울역 뒤편 골목길에 위치한 개미슈퍼는 오랜 세월을 고스란히 간직한 자그마한 구멍가게이다.','04303 서울 용산구 청파로85길 33 (서계동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (163,'쉼박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=29578&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','쉼박물관은 잊혀져 가는 문화를 보존하고 현대 문화예술과 접목시켜 새로운 문화를 만들고자 하는 박물관이다.','03015 서울 종로구 세검정로 209-17 (쉼박물관)',0);
