Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (166,'aT센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=29561&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','aT센터는 국제적인 전시, 컨벤션과 무역 비즈니스가 한 곳에서 이루어지는 새로운 스타일의 전시, 컨벤션센터이다.','06774 서울 서초구 강남대로 27 (양재동, AT센터)',0);
