Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (170,'백범광장공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=28656&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','백범광장공원은 서울 중구 회현동 남산공원을 올라가는 도중 산 중턱에 위치한다.','04633 서울 중구 퇴계로8길 49-4',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (117,'초전섬유퀼트박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6465&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','초전섬유퀼트박물관은 1998년에 설립된 섬유 및 퀼트 작품을 전시하는 박물관이다.','04630 서울 중구 퇴계로18길 66 (제일빌딩)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (118,'잠실대교','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=41095&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울특별시 광진구 자양동과 송파구 잠실동 27번지 사이에 위치한 한강에 건설한 서울의 6번째 다리. 잠실동과 연결되는 다리라 잠실대교라고 하였다.','05502 서울 송파구 한가람로 65 (잠실동, 한강사업본부 잠실안내센터)',0);
