Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (120,'국립기상박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=40770&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','조선시대부터 근현대까지 우리나라 기상문화를 연구하고, 보존하는 국내 최초 기상과학역사 박물관입니다. 서양보다 200여년 앞서 발명된, 세계에서 현존하는 유일한 측우기 ‘공주 충청감영 측우기(公州 忠淸監營 測雨器)’를 소장하고 있습니다.','03178 서울 종로구 송월길 52 (송월동, 국립기상박물관)',0);
