Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (98,'손기정기념관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6996&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','손기정기념관은 손기정 선수의 뜻을 기리기 위해 손기정 선수의 모교인 양정의숙을 고쳐 그의 탄생 100주년인 2012년에 개관하였다.','04501 서울 중구 손기정로 101 (손기정 체육공원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (99,'일민미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2252&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','일민미술관은 일민 김상만을 기념하여 1996년에 세운 미술관으로 종로구 세종로에 위치해있다.','03187 서울 종로구 세종대로 152 (세종로, 일민미술관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (100,'정동길','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=889&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','정동길에 붙는 수식어들이 몇 개 있다. 서울에 몇 안 남은 고풍스러운, 인사동이나 삼청동처럼 사람으로 들끓지 않고 여유로운 분위기를 잘 지킨, 산책하기 좋은, 문화적 냄새가 물씬 풍기는, 장사꾼들의 야단스러움으로부터 해방될 수 있는 유일한 동네, 가로수가 예쁜 거리 등등. 모두 맞는 말이다.','04516 서울 중구 정동길 2 (충정로1가)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (101,'대각사','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5018&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','창덕궁 후원 앞에 위치한 대각사는 1911년 창건되었다.','03134 서울 종로구 율곡로10길 87 (대각사)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (102,'아트선재센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2406&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','아트선재센터는 경주시에 있는 선재미술관의 분관','03062 서울 종로구 율곡로3길 87 (소격동, 아트선재센타)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (103,'경교장','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1151&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','경교장은 대한민국 임시정부의 주석이었던 백범 김구(金九)가 사용했던 개인 사저로 서울 종로구에 있다.','03181 서울 종로구 새문안로 29 (경교장)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (104,'춘원당 한의약박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2637&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','2008년 개관한 춘원당 한방박물관은 탕전실, 품질검사실 및 문화공간, 진료실, 치료실 등으로 총 지하 1층, 지상 6층으로 이뤄져 있다.','03139 서울 종로구 돈화문로9길 27 (춘원당한방박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (105,'만해한용운 심우장','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1399&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','성북동 꼭대기 북향 집서울 성북구 성북동에는 문화유산이 많다. 한성대역 입구에서 삼청각 방향으로 걷다 보면 길의 좌우로 수많은 역사 유적들이 얼굴을 내민다.','02879 서울 성북구 성북로29길 24 (만해 한용운 심우장)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (106,'의릉','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5208&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','성북구 석관동 한국예술종합학교 내부에 자리해 있는 조선 20대 왕 경종과 선의왕후의 무덤인 의릉은 일반적으로 나란히 놓이는 쌍릉과 달리 왕과 왕비의 능이 앞뒤로 배치돼 있다.','02789 서울 성북구 화랑로32길 146-37 (의릉)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (107,'경희대학교 자연사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6957&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','1978년에 지어진 경희대학교 자연사박물관은 경희대학교에서 설립하고 운영하는 박물관','02447 서울특별시 동대문구 경희대로 26 자연사박물관',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (108,'영휘원 숭인원(홍릉)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4525&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','청량리동에 위치한 조선 제26대 왕 고종 후비 선헌귀비 엄씨의 묘소인 영휘원은 1991년 사적 제361호로 지정되었다.','02456 서울 동대문구 홍릉로 90 (영휘원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (109,'반포대교 야경','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=16325&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','반포대교는 용산구와 서초구를 잇는 2층 교량으로 무지개 분수 쇼와 여의도 불꽃축제 기간에는 불꽃놀이를 구경할 수 있는 곳이다.','06500 서울 서초구 올림픽대로 2085-14',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (110,'암사동 선사주거지','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2175&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','우리나라의 대표적인 신석기시대 유적인 암사동 선사 유적지에서는 기원전 5,000년 전후의 선사시대 사람들의 생활상을 엿볼 수 있다.','05239 서울 강동구 올림픽로 875 (서울 암사동 유적)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (111,'서울대학교 미술관 MoA','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3319&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서울대학교 미술관 MoA는 대학교 건물 사이에 자리 잡고 있다. 세계적인 건축가 렘 쿨하스가 설계한 건물로 전시와 교육이 함께 진행된다.','08826 서울 관악구 관악로 1 (신림동, 서울대학교) 서울대학교 미술관 (서울대학교 내)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (112,'떡박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2039&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','떡박물관은 우리 조상들의 슬기로웠던 삶의 모습과 숨결을 느낄 수 있는 체험공간이다.','03132 서울 종로구 돈화문로 71 (와룡동, 떡박물관)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (113,'사육신공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4513&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','사육신공원은 한강대교와 노량진역 언덕에 있는 서울특별시 유형문화재 8번 사육신묘를 가꾸어 만들어졌다.','06902 서울 동작구 노량진로 191 (노량진동, 사육신묘지공원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (114,'광희문','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=23605&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','시구문(屍軀門) ·수구문(水口門)이라고도 하였으며 서소문(西小門)과 함께 시신(屍身)을 내보내던 문이다.','04612 서울 중구 퇴계로 350 (신당동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (115,'아르코 미술관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=18992&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','아르코 미술관은 과거 국립서울대학교 터에 한국문화예술진흥원 산하 미술회관으로 개관되었다.','03087 서울 종로구 동숭길 3 (동숭동, 한국문화예술진흥원)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (116,'윤봉길 의사 기념관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3759&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서초구 양재동에 위치한 윤봉길의사 기념관은 지상 2층 규모로 설립되었다.','06773 서울 서초구 매헌로 99',0);
