Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (147,'성신여대 복식박물관 및 자연사박물관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=33828&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','성신여대 제2캠퍼스인 운정그린캠퍼스에는 있는 정원(淨源) 박광훈 복식박물관과 자연사박물관에서 전통 복식과 자연의 역사를 배워 보세요.','01133 서울 강북구 도봉로76가길 55 (미아동, 성신여자대학교운정그린캠퍼스) 운정그린캠퍼스 B1',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (148,'서울하수도과학관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=33825&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','국내외 하수도의 역사?기술?미래상을 전시하고 있는 과학관과 하수처리시설을 직접 견학할 수 있는 물재생센터를 함께 운영하는 현장 중심형 공간입니다.','04809 서울 성동구 자동차시장3길 64 (용답동) 서울하수도과학관',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (149,'서울도시재생이야기관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=33824&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울도시재생이야기관은 도시재생에 대한 정보와 비전을 나누고 도시재생을 함께 만드는 사람들의 발자취를 공유하는 공간입니다.','03178 서울 종로구 송월길 2 (신문로2가, 서울도시건축센터)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (267,'통문관','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=25930&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','통문관은 1934년부터 이어져 왔다. 우리 귀에 익은 국보급, 보물급 문화재들이 통문관을 거쳐 세상의 빛을 보게 됐다.','03145 서울 종로구 인사동길 55-1 (관훈동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (268,'납청놋전','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=25928&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','납청놋전은 납청 지역에서 만들던 그 방식을 그대로 이어오고 있는 놋그릇 집이다.','03146 서울 종로구 인사동10길 5 (관훈동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (269,'갤러리 3안','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=25060&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','삼청동에 개관한 갤러리 3안은 회화, 영상, 조각, 설치 외 다양한 예술 분야를 다루고 있으며 구애받지 않는 실험 정신을 가진 아티스트들의 작품을 감상할 수 있다.','03053 서울 종로구 북촌로 137-7 (삼청동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (270,'인천공항 제2여객터미널 관광정보센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24807&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','인천공항 제2여객터미널에 위치한 관광정보센터로 2018년 1월 18일에 개관하였다.','22382 인천 중구 공항로 272 (운서동, 인천공항) 제2여객터미널 입국장',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (271,'SJ쿤스트할레','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24732&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','SJ쿤스트할레는 회의과 토론을 하는 문화예술적 플랫폼으로 만들어져 전시, 파티, 공연, 패션쇼, 워크숍 같은 프로그램과 연계된 일상 예술을 제공한다.','06054 서울 강남구 언주로148길 5 (논현동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (272,'종로양복점','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24708&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','종로 양복점은 1916년부터 이어져 왔다. 자그만치 100년이라는 시간이 흘렀다. 가게로 들어가면 오래된 다리미와 재단용 가위가 진열되어 있어 박물관을 연상케한다.','04551 서울 중구 수표로 45 (저동2가, 비즈센터)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (273,'국선옻칠','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24705&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','국선옻칠은 1977년부터 이어온 나전칠기 공예품을 파는 오래된 가게이다. 40년의 역사를 가진 공예점이며, 2대에 걸쳐 가게를 운영하고 있다.','03195 서울 종로구 창경궁로 88 (예지동) 광장3층 2390호',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (274,'구하산방','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24703&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','인사동 구하산방은 1915년 문을 열었다. 고종 황제와 순종 황제가 찾았던 붓집으로 100년이 지난 지금까지 문방사우를 팔고 있다.','03162 서울 종로구 인사동5길 11 (인사동)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (275,'동대문디자인플라자 (DDP)','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24679&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','2006년 서울특별시청이 계획한 동대문디자인플라자(DDP)는 2014년 3월 21일 문을 열었다.','04566 서울 중구 을지로 281 (을지로7가, 디자인장터)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (276,'코엑스','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=24663&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','이 컨벤션센터는 국제회의와 국제적 리셉션, 업무 세미나와 소규모 회의 같은 대형 이벤트를 제공하는 콘퍼런스홀이 특징이다.','06164 서울 강남구 영동대로 513 (삼성동, 코엑스)',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (254,'영등포관광정보센터','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27191&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','영등포관광정보센터는 서울 서남권 중심거점이자 하루 수십만의 유동인구가 지나고 있는 타임스퀘어 광장에 2017년 9월 개관했다.','07305 서울 영등포구 영중로 15 (영등포동4가, 타임스퀘어)',0);
