Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (256,'북촌마을관광안내소','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27189&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','북촌마을안내소는 정독도서관 내 부지를 활용하여 2014년 8월 건립되었으며 영어, 일본어, 중국어가 가능한 관광안내사를 통해 관광객을 위한 관광정보 제공 및 통역 안내서비스를 제공한다.','03055 서울 종로구 북촌로5길 48 (화동, 정독도서관) 정독도서관 부지내, 서울교육박물관 앞',0);
Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (257,'초대길','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27112&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','초대길은 강북구 근현대사기념관 개관을 기념하여 새롭게 기획된 둘레길 코스이다.','01013 서울 강북구 4.19로 114 (수유동) 근현대사기념관 (출발)',0);
