Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (260,'박인당','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=26954&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','박인당은 대한민국 정부가 인정한 명장이 도장을 파주는 곳이다.','03189 서울 종로구 청계천로 55 (관철동, 대신빌딩) 302호',0);
