Insert into HR.SEOUL_LOCATION (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (262,'공근혜갤러리','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=26676&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','공근혜갤러리는 2005년 개관 이래로 해외 유명 사진작가들을 국내에 처음 소개하며 한국 사진계에 큰 영향력을 끼친 화랑으로 이름을 알려왔다.','03049 서울 종로구 삼청로7길 38 (삼청동)',0);
